CREATE TABLE log_table (
id INTEGER PRIMARY KEY AUTOINCREMENT,
type INTEGER NOT NULL,
uid INTEGER,
username VARCHAR,
view_id INTEGER,
share_name VARCHAR,
share_type INTEGER,
time INTEGER NOT NULL,
s1 TEXT COLLATE NOCASE,
