p4 TEXT COLLATE NOCASE,
p5 TEXT COLLATE NOCASE,
target_view_id INTEGER DEFAULT 0,
target_share_name VARCHAR DEFAULT '',
target_share_type INTEGER DEFAULT 0
, client_type BigInt DEFAULT 0, ip_address VarChar DEFAULT '');
CREATE INDEX log_table_type_index ON log_table(type);
CREATE INDEX log_table_uid_index ON log_table(uid);
CREATE INDEX log_table_username_index ON log_table(username);
CREATE INDEX log_table_view_id_index ON log_table(view_id);
CREATE INDEX log_table_share_name_index ON log_table(share_name);
CREATE INDEX log_table_time_index ON log_table(time);
CREATE INDEX log_table_target_view_id_index ON log_table(target_view_id);
CREATE INDEX log_table_target_share_name_index ON log_table(target_share_name);
CREATE INDEX log_table_ip_address_index ON log_table(ip_address);
CREATE INDEX log_username_time_index ON log_table(username, time);

